import React, { useEffect, useState } from 'react';
import { Icon, IconBtn } from '@capital/component';
import { showToasts } from '@capital/common';
import { parseMusicCardFromContent, b64decode } from '../../utils/share';
import { getPicUrl, searchAlbumTracks, searchMusic } from '../../api/musicApi';
import { usePlayerStore } from '../../store/playerStore';
import { createPlaylist, addSongToPlaylist } from '../../utils/storage';
import { MusicSource, Song } from '../../const';

interface Props {
  payload: { content: string };
}

const cardStyle: React.CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  gap: 10,
  maxWidth: 340,
  padding: 10,
  marginTop: 6,
  borderRadius: 10,
  background: 'var(--tc-content-background-color, rgba(120,120,120,0.08))',
  border: '1px solid rgba(120,120,120,0.18)',
};

const coverStyle: React.CSSProperties = {
  width: 48,
  height: 48,
  borderRadius: 8,
  objectFit: 'cover',
  background: 'linear-gradient(135deg,#667eea,#764ba2)',
  flexShrink: 0,
};

export const MusicCard: React.FC<Props> = React.memo(({ payload }) => {
  const parsed = parseMusicCardFromContent(payload.content || '');
  const [cover, setCover] = useState<string>('');
  const playSong = usePlayerStore((s) => s.playSong);

  useEffect(() => {
    if (!parsed) return;
    const pic = parsed.params.pic;
    const source = (parsed.params.source || 'netease') as MusicSource;
    if (pic) {
      getPicUrl(pic, source).then(setCover).catch(() => undefined);
    }
  }, [parsed?.params.pic]);

  if (!parsed) return null;

  const { type, params } = parsed;
  const source = (params.source || 'netease') as MusicSource;

  const handlePlaySong = () => {
    const song: Song = {
      id: params.id,
      source,
      name: params.name,
      artist: params.artist,
      album: params.album,
      pic_id: params.pic,
      lyric_id: params.lyric,
    };
    playSong(song, [song]);
  };

  const handlePlayAlbum = async () => {
    showToasts('正在加载专辑曲目...', 'info');
    const songs = await searchAlbumTracks(params.album, source);
    if (songs.length === 0) {
      showToasts('未找到专辑曲目', 'warning');
      return;
    }
    playSong(songs[0], songs);
  };

  const handleSearchArtist = async () => {
    showToasts('正在搜索歌手作品...', 'info');
    const songs = await searchMusic(params.artist, source, 20);
    if (songs.length === 0) {
      showToasts('未找到相关歌曲', 'warning');
      return;
    }
    playSong(songs[0], songs);
  };

  const handleImportPlaylist = () => {
    try {
      const list: any[] = JSON.parse(b64decode(params.data));
      const playlist = createPlaylist(params.name || '导入的歌单');
      list.forEach((item) => {
        addSongToPlaylist(playlist.id, {
          id: item.i,
          source: item.s,
          name: item.n,
          artist: item.a,
          album: item.al,
          pic_id: item.p,
          lyric_id: item.l,
        });
      });
      showToasts(`已导入歌单《${playlist.name}》(${list.length}首)`, 'success');
    } catch {
      showToasts('导入失败', 'error');
    }
  };

  const handlePlayPlaylist = () => {
    try {
      const list: any[] = JSON.parse(b64decode(params.data));
      const songs: Song[] = list.map((item) => ({
        id: item.i,
        source: item.s,
        name: item.n,
        artist: item.a,
        album: item.al,
        pic_id: item.p,
        lyric_id: item.l,
      }));
      if (songs.length > 0) {
        playSong(songs[0], songs);
      }
    } catch {
      showToasts('播放失败', 'error');
    }
  };

  if (type === 'song') {
    return (
      <div style={cardStyle}>
        {cover ? <img src={cover} style={coverStyle} /> : <div style={coverStyle} />}
        <div style={{ flex: 1, minWidth: 0 }}>
          <div style={{ fontWeight: 600, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
            {params.name}
          </div>
          <div style={{ opacity: 0.6, fontSize: 12, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
            {params.artist} {params.album ? `· ${params.album}` : ''}
          </div>
        </div>
        <IconBtn icon="mdi:play-circle" size="large" title="播放" onClick={handlePlaySong} />
      </div>
    );
  }

  if (type === 'album') {
    return (
      <div style={cardStyle}>
        {cover ? <img src={cover} style={coverStyle} /> : <div style={coverStyle} />}
        <div style={{ flex: 1, minWidth: 0 }}>
          <div style={{ fontWeight: 600 }}>{params.album}</div>
          <div style={{ opacity: 0.6, fontSize: 12 }}>专辑 · {params.artist}</div>
        </div>
        <IconBtn icon="mdi:play-circle" size="large" title="播放专辑" onClick={handlePlayAlbum} />
      </div>
    );
  }

  if (type === 'artist') {
    return (
      <div style={cardStyle}>
        <div style={{ ...coverStyle, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
          <Icon icon="mdi:account-music" color="#fff" />
        </div>
        <div style={{ flex: 1, minWidth: 0 }}>
          <div style={{ fontWeight: 600 }}>{params.artist}</div>
          <div style={{ opacity: 0.6, fontSize: 12 }}>歌手</div>
        </div>
        <IconBtn icon="mdi:play-circle" size="large" title="播放热门作品" onClick={handleSearchArtist} />
      </div>
    );
  }

  if (type === 'playlist') {
    return (
      <div style={cardStyle}>
        <div style={{ ...coverStyle, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
          <Icon icon="mdi:playlist-music" color="#fff" />
        </div>
        <div style={{ flex: 1, minWidth: 0 }}>
          <div style={{ fontWeight: 600 }}>{params.name}</div>
          <div style={{ opacity: 0.6, fontSize: 12 }}>歌单 · {params.count}首</div>
        </div>
        <div style={{ display: 'flex' }}>
          <IconBtn icon="mdi:play-circle" size="large" title="播放" onClick={handlePlayPlaylist} />
          <IconBtn icon="mdi:download" size="large" title="导入到我的歌单" onClick={handleImportPlaylist} />
        </div>
      </div>
    );
  }

  return null;
});
MusicCard.displayName = 'MusicCard';
