import React, { useEffect, useState } from 'react';
import { usePlayerStore } from '../../store/playerStore';
import { useSettingsStore } from '../../store/settingsStore';
import { updateMediaSessionMeta } from '../../utils/mediaKeys';
import { getPicUrl } from '../../api/musicApi';
import { MiniBar, CollapsedDot } from './MiniBar';
import { FloatingLyrics } from './FloatingLyrics';
import { FullPlayer } from './FullPlayer';
import { PLUGIN_ID } from '../../const';

type ViewMode = 'collapsed' | 'mini' | 'lyrics' | 'full';

const PANEL_ROUTE_MATCH = `/custom/${PLUGIN_ID}/musicpanel`;

/**
 * 音乐面板自身已经内置了完整的播放控制/歌词/封面展示，
 * 所以停留在音乐面板页面时不需要再叠加一个悬浮播放器；
 * 只有离开音乐面板(切回聊天/其他页面)时才显示悬浮播放器。
 *
 * 用轮询而非监听 history/popstate，是因为不确定宿主使用的路由库
 * 版本/内部事件机制，轮询是最不容易受宿主实现细节影响的稳妥方式。
 */
function useIsOnMusicPanel(): boolean {
  const [onPanel, setOnPanel] = useState(() =>
    window.location.pathname.includes(PANEL_ROUTE_MATCH)
  );

  useEffect(() => {
    const timer = setInterval(() => {
      const next = window.location.pathname.includes(PANEL_ROUTE_MATCH);
      setOnPanel((prev) => (prev !== next ? next : prev));
    }, 300);
    return () => clearInterval(timer);
  }, []);

  return onPanel;
}

export const PlayerRoot: React.FC = () => {
  const song = usePlayerStore((s) => s.currentSong);
  const visible = usePlayerStore((s) => s.visible);
  const setVisible = usePlayerStore((s) => s.setVisible);
  const settings = useSettingsStore((s) => s.settings);
  const onMusicPanel = useIsOnMusicPanel();
  const [view, setView] = useState<ViewMode>(
    settings.playerStyle === 'lyrics' ? 'lyrics' : settings.playerStyle === 'full' ? 'full' : 'mini'
  );

  useEffect(() => {
    if (!song) return;
    updateMediaSessionMeta({ title: song.name, artist: song.artist, album: song.album });
    if (song.pic_id) {
      getPicUrl(song.pic_id, song.source)
        .then((url) => updateMediaSessionMeta({ title: song.name, artist: song.artist, album: song.album, artwork: url }))
        .catch(() => undefined);
    }
  }, [song?.id, song?.source]);

  // 停留在音乐面板本身时，面板内已经有完整的播放信息展示，不需要悬浮播放器
  if (onMusicPanel) {
    return null;
  }

  if (!visible) {
    return <CollapsedDot onOpen={() => setVisible(true)} />;
  }

  if (view === 'lyrics') {
    return (
      <FloatingLyrics
        onExpand={() => setView('full')}
        onClose={() => setVisible(false)}
      />
    );
  }

  if (view === 'full') {
    return <FullPlayer onCollapse={() => setView('mini')} onClose={() => setVisible(false)} />;
  }

  return (
    <MiniBar onExpand={() => setView(settings.playerStyle === 'lyrics' ? 'lyrics' : 'full')} onClose={() => setVisible(false)} />
  );
};
