import React, { useState } from 'react';
import { Icon } from '@capital/component';
import { Search } from './Search';
import { Playlists } from './Playlists';
import { SettingsPanel } from './SettingsPanel';
import { Sidebar } from './Sidebar';
import { TransportBar } from './TransportBar';
import { Translate } from '../../translate';

type TabKey = 'search' | 'playlists' | 'settings';

const TABS: { key: TabKey; label: string; icon: string }[] = [
  { key: 'search', label: Translate.search, icon: 'mdi:magnify' },
  { key: 'playlists', label: Translate.playlists, icon: 'mdi:playlist-music' },
  { key: 'settings', label: Translate.settings, icon: 'mdi:cog' },
];

/**
 * 整体布局参考设计图: 顶部 Tab 切换栏 / 左侧内容列表 + 右侧封面歌词栏 / 底部常驻播放条
 */
export const MusicPanel: React.FC = React.memo(() => {
  const [tab, setTab] = useState<TabKey>('search');

  return (
    <div style={{ display: 'flex', flexDirection: 'column', height: '100%', width: '100%' }}>
      {/* 顶部 Tab 栏 */}
      <div style={{ display: 'flex', borderBottom: '1px solid rgba(120,120,120,0.2)' }}>
        {TABS.map((t) => (
          <div
            key={t.key}
            onClick={() => setTab(t.key)}
            style={{
              flex: 1,
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              gap: 6,
              padding: '12px 0',
              cursor: 'pointer',
              fontSize: 13,
              fontWeight: tab === t.key ? 700 : 400,
              color: tab === t.key ? '#22c55e' : 'inherit',
              borderBottom: tab === t.key ? '2px solid #22c55e' : '2px solid transparent',
            }}
          >
            <Icon icon={t.icon} width={16} />
            {t.label}
          </div>
        ))}
      </div>

      {/* 中间内容区: 左侧列表 + 右侧封面/歌词栏 (设置页不需要侧栏，占满全宽) */}
      <div style={{ flex: 1, display: 'flex', overflow: 'hidden', minHeight: 0 }}>
        <div style={{ flex: 1, minWidth: 0, overflow: 'hidden' }}>
          {tab === 'search' && <Search />}
          {tab === 'playlists' && <Playlists />}
          {tab === 'settings' && <SettingsPanel />}
        </div>
        {tab !== 'settings' && <Sidebar />}
      </div>

      {/* 底部常驻播放条 */}
      <TransportBar />
    </div>
  );
});
MusicPanel.displayName = 'MusicPanel';
