import { createStore as create } from '../utils/createStore';
import { LyricLine, PlayMode, Song } from '../const';
import { getSongUrl, getLyric } from '../api/musicApi';
import { findCurrentLyricIndex, mergeBilingualLrc, parseLrc } from '../utils/lrc';
import { getSettingsSnapshot } from './settingsStore';
import { pushHistory } from '../utils/storage';

interface PlayerState {
  queue: Song[];
  currentIndex: number;
  currentSong: Song | null;
  playing: boolean;
  loading: boolean;
  currentTime: number;
  duration: number;
  volume: number;
  muted: boolean;
  mode: PlayMode;
  lyrics: LyricLine[];
  currentLyricIndex: number;
  visible: boolean; // 是否展示播放器 UI (关闭按钮控制)

  playSong: (song: Song, queue?: Song[]) => Promise<void>;
  togglePlay: () => void;
  next: () => void;
  prev: () => void;
  seek: (time: number) => void;
  setVolume: (v: number) => void;
  toggleMute: () => void;
  cycleMode: () => void;
  setVisible: (visible: boolean) => void;
  enqueue: (songs: Song[]) => void;
}

let audio: HTMLAudioElement | null = null;

function getAudio(): HTMLAudioElement {
  if (!audio) {
    audio = new Audio();
    audio.preload = 'auto';
  }
  return audio;
}

export const usePlayerStore = create<PlayerState>((set, get) => {
  const a = getAudio();

  a.addEventListener('timeupdate', () => {
    const { lyrics } = get();
    const currentTime = a.currentTime;
    set({
      currentTime,
      currentLyricIndex: findCurrentLyricIndex(lyrics, currentTime),
    });
  });
  a.addEventListener('loadedmetadata', () => set({ duration: a.duration || 0 }));
  a.addEventListener('play', () => set({ playing: true }));
  a.addEventListener('pause', () => set({ playing: false }));
  a.addEventListener('waiting', () => set({ loading: true }));
  a.addEventListener('canplay', () => set({ loading: false }));
  a.addEventListener('ended', () => {
    const { mode } = get();
    if (mode === 'loop') {
      a.currentTime = 0;
      a.play();
    } else {
      get().next();
    }
  });

  return {
    queue: [],
    currentIndex: -1,
    currentSong: null,
    playing: false,
    loading: false,
    currentTime: 0,
    duration: 0,
    volume: 0.8,
    muted: false,
    mode: 'order',
    lyrics: [],
    currentLyricIndex: -1,
    visible: true,

    enqueue: (songs) => {
      set({ queue: [...get().queue, ...songs] });
    },

    playSong: async (song, queue) => {
      const nextQueue = queue ?? get().queue;
      const idx = nextQueue.findIndex((s) => s.id === song.id && s.source === song.source);

      set({
        currentSong: song,
        queue: nextQueue,
        currentIndex: idx >= 0 ? idx : get().currentIndex,
        loading: true,
        lyrics: [],
        currentLyricIndex: -1,
        currentTime: 0,
        visible: true,
      });

      pushHistory(song);

      try {
        const settings = getSettingsSnapshot();
        const [urlInfo, lyricInfo] = await Promise.all([
          getSongUrl(song.id, song.source, settings.quality),
          song.lyric_id
            ? getLyric(song.lyric_id, song.source).catch(() => null)
            : Promise.resolve(null),
        ]);

        if (get().currentSong?.id !== song.id) return; // 用户已切歌

        if (lyricInfo) {
          const origin = parseLrc(lyricInfo.lyric || '');
          const tran = parseLrc(lyricInfo.tlyric || '');
          set({ lyrics: mergeBilingualLrc(origin, tran) });
        }

        if (urlInfo?.url) {
          a.src = urlInfo.url;
          a.volume = get().muted ? 0 : get().volume;
          await a.play().catch(() => undefined);
        }
      } finally {
        set({ loading: false });
      }
    },

    togglePlay: () => {
      if (!a.src) return;
      if (a.paused) {
        a.play();
      } else {
        a.pause();
      }
    },

    next: () => {
      const { queue, currentIndex, mode } = get();
      if (queue.length === 0) return;
      let nextIdx: number;
      if (mode === 'random') {
        nextIdx = Math.floor(Math.random() * queue.length);
      } else {
        nextIdx = (currentIndex + 1) % queue.length;
      }
      get().playSong(queue[nextIdx], queue);
    },

    prev: () => {
      const { queue, currentIndex, mode } = get();
      if (queue.length === 0) return;
      let prevIdx: number;
      if (mode === 'random') {
        prevIdx = Math.floor(Math.random() * queue.length);
      } else {
        prevIdx = (currentIndex - 1 + queue.length) % queue.length;
      }
      get().playSong(queue[prevIdx], queue);
    },

    seek: (time) => {
      a.currentTime = time;
      set({ currentTime: time });
    },

    setVolume: (v) => {
      a.volume = v;
      a.muted = false;
      set({ volume: v, muted: false });
    },

    toggleMute: () => {
      const muted = !get().muted;
      a.muted = muted;
      set({ muted });
    },

    cycleMode: () => {
      const order: PlayMode[] = ['order', 'random', 'loop'];
      const idx = order.indexOf(get().mode);
      set({ mode: order[(idx + 1) % order.length] });
    },

    setVisible: (visible) => set({ visible }),
  };
});

export function getAudioElement() {
  return getAudio();
}
