import React from 'react';
import * as CapitalCommon from '@capital/common';
import { PLUGIN_ID } from './const';
import { Translate } from './translate';
import { MusicPanel } from './components/panel';
import { MusicCard } from './components/card/MusicCard';
import { parseMusicCardFromContent } from './utils/share';
import { openMusicShareModal } from './components/ChatShareButton';
import { mountGlobalPlayer } from './components/player/mount';
import { initMediaKeys } from './utils/mediaKeys';

const {
  regCustomPanel,
  regPluginCardItem,
  regMessageExtraParser,
  regChatInputAction,
  regPluginSettings,
  showToasts,
} = CapitalCommon as any;

console.log(`Plugin ${PLUGIN_ID} is loaded`);

/**
 * 安全注册: 兼容不同版本 Tailchat 宿主可能缺失某些较新 API 的情况。
 * 任意一项注册失败都只会跳过该功能并打印警告，不会导致整个插件加载失败。
 *
 * 注意: 本插件刻意不使用任何 `import()` 动态分包。Tailchat 的 mini-star 运行时
 * 加载"插件自身产生的子 chunk"时，固定按 `<Tailchat前端origin>/plugins/<插件名>/xxx.js`
 * 拼接地址，而不是相对于插件 manifest.url 实际所在的位置——这意味着任何未与
 * Tailchat 前端部署在同一目录下的第三方插件，只要产生多个文件(动态 import)，
 * 除入口文件外的其他分包都会 404 / 加载超时。因此这里始终使用同步 import，
 * 把所有代码打进单一 index.js，从根源上避免这个问题。
 */
function safe(label: string, fn: () => void) {
  try {
    fn();
  } catch (e) {
    console.warn(`[${PLUGIN_ID}] Skip feature "${label}": current Tailchat host may not support it.`, e);
  }
}

/**
 * 左下角三个点(更多面板)上方的音乐面板入口
 */
safe('custom-panel', () => {
  if (typeof regCustomPanel !== 'function') throw new Error('regCustomPanel unavailable');
  regCustomPanel({
    position: 'navbar-more',
    icon: 'mdi:music-box-multiple',
    name: `${PLUGIN_ID}/musicpanel`,
    label: Translate.panelLabel,
    render: MusicPanel,
  });
});

/**
 * 挂载全局悬浮播放器 (右下角小播放器 / 悬浮歌词 / 完整播放器)
 * 与面板是否打开无关，在插件加载后即挂载
 */
safe('global-player', () => {
  mountGlobalPlayer();
});

/**
 * 消息卡片: 歌曲 / 专辑 / 歌手 / 歌单
 */
safe('card-item', () => {
  if (typeof regPluginCardItem !== 'function') throw new Error('regPluginCardItem unavailable');
  regPluginCardItem(`${PLUGIN_ID}/music-card`, { render: MusicCard });
});

/**
 * 消息额外解析: 检测消息正文中的音乐分享标记, 在消息下方渲染富媒体卡片
 * (使用 buildRegList 的 additive 注册方式, 不会覆盖其他插件如 bbcode 的消息渲染)
 */
safe('message-extra-parser', () => {
  if (typeof regMessageExtraParser !== 'function') throw new Error('regMessageExtraParser unavailable');
  regMessageExtraParser({
    name: `${PLUGIN_ID}/music-card-parser`,
    render: (payload: { content: string }) => {
      const parsed = parseMusicCardFromContent(payload.content || '');
      if (!parsed) return null;
      return React.createElement(MusicCard, { payload });
    },
  });
});

/**
 * 聊天输入框 "+" 菜单: 分享音乐
 */
safe('chat-input-action', () => {
  if (typeof regChatInputAction !== 'function') throw new Error('regChatInputAction unavailable');
  regChatInputAction({
    label: Translate.shareToChat,
    onClick: (actions: any) => {
      try {
        openMusicShareModal(actions);
      } catch (e) {
        if (typeof showToasts === 'function') {
          showToasts('打开分享面板失败', 'error');
        }
      }
    },
  });
});

/**
 * 系统设置中提供的简要开关 (完整设置见插件面板内设置Tab)
 */
safe('plugin-settings', () => {
  if (typeof regPluginSettings !== 'function') throw new Error('regPluginSettings unavailable');
  regPluginSettings({
    name: `${PLUGIN_ID}/mediaKeysEnabled`,
    label: Translate.mediaKeys,
    position: 'system',
    type: 'boolean',
    defaultValue: true,
  });
});

/**
 * 初始化媒体快捷键 (系统媒体键 + 页面内自定义快捷键)
 */
safe('media-keys', () => {
  initMediaKeys();
});
