import React, { useRef, useState } from 'react';
import { Icon } from '@capital/component';
import { usePlayerStore } from '../../store/playerStore';
import { useSettingsStore } from '../../store/settingsStore';
import { PlayControls } from './Controls';

export const FloatingLyrics: React.FC<{ onExpand: () => void; onClose: () => void }> = ({
  onExpand,
  onClose,
}) => {
  const { settings, update } = useSettingsStore((s) => ({ settings: s.settings, update: s.update }));
  const song = usePlayerStore((s) => s.currentSong);
  const lyrics = usePlayerStore((s) => s.lyrics);
  const idx = usePlayerStore((s) => s.currentLyricIndex);

  const dragRef = useRef<{ startX: number; startY: number; origX: number; origY: number } | null>(
    null
  );
  const [pos, setPos] = useState(settings.floatingPos);

  const onMouseDown = (e: React.MouseEvent) => {
    if (settings.floatingLocked) return;
    dragRef.current = {
      startX: e.clientX,
      startY: e.clientY,
      origX: pos.x,
      origY: pos.y,
    };
    const onMove = (ev: MouseEvent) => {
      if (!dragRef.current) return;
      const dx = ev.clientX - dragRef.current.startX;
      const dy = ev.clientY - dragRef.current.startY;
      setPos({ x: Math.max(0, dragRef.current.origX - dx), y: Math.max(0, dragRef.current.origY - dy) });
    };
    const onUp = () => {
      window.removeEventListener('mousemove', onMove);
      window.removeEventListener('mouseup', onUp);
      setPos((p) => {
        update({ floatingPos: p });
        return p;
      });
    };
    window.addEventListener('mousemove', onMove);
    window.addEventListener('mouseup', onUp);
  };

  const current = idx >= 0 ? lyrics[idx] : null;
  const nextLine = idx >= 0 ? lyrics[idx + 1] : lyrics[0];

  return (
    <div
      onMouseDown={onMouseDown}
      style={{
        position: 'fixed',
        right: pos.x,
        bottom: pos.y,
        zIndex: 999999,
        width: 380,
        maxWidth: '90vw',
        padding: '14px 18px',
        borderRadius: 14,
        background: `rgba(10,10,10,${settings.floatingOpacity * 0.6})`,
        cursor: settings.floatingLocked ? 'default' : 'move',
        userSelect: 'none',
        textAlign: 'center',
        opacity: settings.floatingOpacity,
        transition: 'opacity .2s',
      }}
      className="group"
    >
      <div style={{ position: 'absolute', top: 4, right: 6, display: 'flex', gap: 6 }}>
        <Icon
          icon={settings.floatingLocked ? 'mdi:lock' : 'mdi:lock-open-variant'}
          width={14}
          color="#fff"
          style={{ opacity: 0.6, cursor: 'pointer' }}
          onClick={(e: any) => {
            e.stopPropagation();
            update({ floatingLocked: !settings.floatingLocked });
          }}
        />
        <Icon
          icon="mdi:arrow-expand"
          width={14}
          color="#fff"
          style={{ opacity: 0.6, cursor: 'pointer' }}
          onClick={(e: any) => {
            e.stopPropagation();
            onExpand();
          }}
        />
        <Icon
          icon="mdi:close"
          width={14}
          color="#fff"
          style={{ opacity: 0.6, cursor: 'pointer' }}
          onClick={(e: any) => {
            e.stopPropagation();
            onClose();
          }}
        />
      </div>

      {!song ? (
        <div style={{ color: settings.lyricColor, opacity: 0.6, fontSize: settings.lyricSize }}>
          暂无播放歌曲
        </div>
      ) : (
        <>
          <div
            style={{
              color: settings.lyricHighlightColor,
              fontSize: settings.lyricSize,
              fontWeight: 700,
              lineHeight: 1.5,
              textShadow: '0 1px 4px rgba(0,0,0,0.6)',
            }}
          >
            {current?.text || song.name}
          </div>
          {settings.bilingualLyric && current?.tran && (
            <div
              style={{
                color: settings.lyricColor,
                fontSize: settings.lyricSize * 0.72,
                opacity: 0.85,
                marginTop: 2,
              }}
            >
              {current.tran}
            </div>
          )}
          <div
            style={{
              color: settings.lyricColor,
              fontSize: settings.lyricSize * 0.65,
              opacity: 0.45,
              marginTop: 4,
            }}
          >
            {nextLine?.text || ''}
          </div>

          <div
            style={{
              marginTop: 10,
              display: 'flex',
              justifyContent: 'center',
              opacity: 0,
              transition: 'opacity .15s',
            }}
            onMouseEnter={(e) => (e.currentTarget.style.opacity = '1')}
            onMouseLeave={(e) => (e.currentTarget.style.opacity = '0')}
          >
            <PlayControls size={16} color="#fff" />
          </div>
        </>
      )}
    </div>
  );
};
