import { createStore as create } from '../utils/createStore';
import { MusicSource, PlayerStyle, STORAGE_KEYS } from '../const';

export interface ShortcutMap {
  playPause: string;
  next: string;
  prev: string;
  volumeUp: string;
  volumeDown: string;
}

export interface MusicSettings {
  playerStyle: PlayerStyle;
  defaultSource: MusicSource;
  quality: 128 | 192 | 320 | 740 | 999;
  mediaKeysEnabled: boolean;
  shortcuts: ShortcutMap;
  lyricSize: number; // px
  lyricColor: string;
  lyricHighlightColor: string;
  lyricOpacity: number; // 0-1
  bilingualLyric: boolean;
  floatingLocked: boolean;
  floatingOpacity: number; // 0-1
  floatingPos: { x: number; y: number };
  theme: 'auto' | 'light' | 'dark' | 'colorful';
}

const DEFAULT_SETTINGS: MusicSettings = {
  playerStyle: 'mini',
  defaultSource: 'netease',
  quality: 320,
  mediaKeysEnabled: true,
  shortcuts: {
    playPause: 'Alt+P',
    next: 'Alt+Right',
    prev: 'Alt+Left',
    volumeUp: 'Alt+Up',
    volumeDown: 'Alt+Down',
  },
  lyricSize: 20,
  lyricColor: '#ffffff',
  lyricHighlightColor: '#22c55e',
  lyricOpacity: 0.9,
  bilingualLyric: true,
  floatingLocked: false,
  floatingOpacity: 0.85,
  floatingPos: { x: 40, y: 80 },
  theme: 'auto',
};

function loadSettings(): MusicSettings {
  try {
    const raw = localStorage.getItem(STORAGE_KEYS.settings);
    if (!raw) return DEFAULT_SETTINGS;
    return { ...DEFAULT_SETTINGS, ...JSON.parse(raw) };
  } catch {
    return DEFAULT_SETTINGS;
  }
}

interface SettingsState {
  settings: MusicSettings;
  update: (patch: Partial<MusicSettings>) => void;
  reset: () => void;
}

export const useSettingsStore = create<SettingsState>((set, get) => ({
  settings: loadSettings(),
  update: (patch) => {
    const next = { ...get().settings, ...patch };
    set({ settings: next });
    localStorage.setItem(STORAGE_KEYS.settings, JSON.stringify(next));
    window.dispatchEvent(new CustomEvent('musicplayer:settings-changed', { detail: next }));
  },
  reset: () => {
    set({ settings: DEFAULT_SETTINGS });
    localStorage.setItem(STORAGE_KEYS.settings, JSON.stringify(DEFAULT_SETTINGS));
  },
}));

export function getSettingsSnapshot(): MusicSettings {
  return useSettingsStore.getState().settings;
}
