import { LyricLine } from '../const';

const LINE_RE = /\[(\d{2}):(\d{2})(?:[.:](\d{1,3}))?\]/g;

/**
 * 解析 LRC 歌词文本为按时间排序的行数组
 */
export function parseLrc(lrc: string): LyricLine[] {
  if (!lrc) {
    return [];
  }

  const lines: LyricLine[] = [];
  const rawLines = lrc.split(/\r?\n/);

  for (const raw of rawLines) {
    const timestamps: number[] = [];
    let match: RegExpExecArray | null;
    LINE_RE.lastIndex = 0;
    while ((match = LINE_RE.exec(raw))) {
      const min = parseInt(match[1], 10);
      const sec = parseInt(match[2], 10);
      const ms = match[3] ? parseInt(match[3].padEnd(3, '0'), 10) : 0;
      timestamps.push(min * 60 + sec + ms / 1000);
    }
    const text = raw.replace(LINE_RE, '').trim();
    if (timestamps.length === 0) {
      continue;
    }
    for (const time of timestamps) {
      lines.push({ time, text });
    }
  }

  return lines.sort((a, b) => a.time - b.time);
}

/**
 * 将原文歌词与翻译歌词按时间戳合并为双语歌词
 */
export function mergeBilingualLrc(origin: LyricLine[], translation: LyricLine[]): LyricLine[] {
  if (translation.length === 0) {
    return origin;
  }

  const tranMap = new Map<number, string>();
  for (const line of translation) {
    tranMap.set(Math.round(line.time * 10), line.text);
  }

  return origin.map((line) => ({
    ...line,
    tran: tranMap.get(Math.round(line.time * 10)),
  }));
}

/**
 * 二分查找当前时间对应的歌词行下标
 */
export function findCurrentLyricIndex(lines: LyricLine[], currentTime: number): number {
  if (lines.length === 0) {
    return -1;
  }
  let lo = 0;
  let hi = lines.length - 1;
  let result = -1;
  while (lo <= hi) {
    const mid = (lo + hi) >> 1;
    if (lines[mid].time <= currentTime) {
      result = mid;
      lo = mid + 1;
    } else {
      hi = mid - 1;
    }
  }
  return result;
}
